const input = $items("Set Input Defaults")[0].json;
const base = {
  project_name: input.project_name,
  neo4j_user: input.neo4j_user,
  neo4j_password: input.neo4j_password,
  neo4j_url: input.neo4j_url
};
const raw = $json.response !== undefined ? $json.response : ($json.body !== undefined ? $json.body : $json);
let cypherText = '';
if (typeof raw === 'string') {
  cypherText = raw;
} else if (raw && typeof raw === 'object' && typeof raw.response === 'string') {
  cypherText = raw.response;
} else {
  cypherText = JSON.stringify(raw);
}
cypherText = cypherText.replace(/```(?:cypher)?\s*/gi, '').replace(/```/g, '').trim();
if (!cypherText || !/MERGE/i.test(cypherText)) {
  throw new Error('Ollama did not return valid Cypher MERGE statements. Response: ' + cypherText.slice(0, 200));
}
return [{ json: { ...base, cypher: cypherText } }];

const cypher = $json.cypher || '';
const project = $json.project_name || 'default-project';
const postProcess = [
  "MATCH (n) WHERE (n:Class OR n:DatatypeProperty OR n:ObjectProperty) AND n.graph IS NULL SET n.graph = 'OntoGraph', n.project = $project",
  "WITH 1 AS dummy",
  "MATCH (n) WHERE (n:Rule OR n:Atom OR n:Builtin OR n:Var OR n:Literal) AND n.graph IS NULL SET n.graph = 'Metagraph', n.project = $project"
].join('\n');
return [{
  json: {
    project_name: $json.project_name,
    neo4j_user: $json.neo4j_user,
    neo4j_password: $json.neo4j_password,
    neo4j_url: $json.neo4j_url,
    cypher: cypher,
    postProcess: postProcess
  }
}];

const payload = $items("Prepare Graph Payload")[0].json;
const cypher = payload.cypher || '';
const mergeCount = (cypher.match(/MERGE/gi) || []).length;
return [{
  json: {
    status: "ok",
    project: payload.project_name,
    database: "neo4j",
    graphs: { ontology: "OntoGraph", rules: "Metagraph" },
    counts: { merge_statements: mergeCount },
    cypher: cypher
  }
}];
